<?php
namespace App\Http\Controllers\Api;
use App\Models\Project;use App\Services\CostAnalyticsService;use Illuminate\Http\Request;use App\Http\Controllers\Controller;
class AnalyticsController extends Controller{public function summary(Request $r,Project $project,CostAnalyticsService $s){$this->authorize('view',$project);return $s->getActualPayments($project,$r->all());} public function byTags(Request $r,Project $project,CostAnalyticsService $s){$this->authorize('view',$project);return $s->getCostByTags($project,$r->all());} public function byMonths(Request $r,Project $project,CostAnalyticsService $s){$this->authorize('view',$project);return $s->getCostByMonths($project,$r->all());} public function byContractors(Request $r,Project $project,CostAnalyticsService $s){$this->authorize('view',$project);return $s->getCostByContractors($project,$r->all());} public function byMaterials(Request $r,Project $project,CostAnalyticsService $s){$this->authorize('view',$project);return $s->getCostByMaterials($project,$r->all());}}
